#include <iostream>
#include <map>
using namespace std;
map<int,int> mmap;
int main()
{
    int n,q;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int t;
        cin>>t;
        mmap[t]=i;
    }
    cin>>q;
    for(int i=1;i<=q;i++)
    {
        int t;
        cin>>t;
        if(mmap.count(t))
        {
            cout<<mmap[t]<<endl;
        }
        else
        {
            cout<<0<<endl;
        }
    }
    return 0;
}
